// ─── PartyBuilderPanel ────────────────────────────────────────────────────────

class PartyBuilderPanel extends UIPanel {
  constructor(heroes, onStart) {
    super('panel-party-builder', { trapFocus: false, zLayer: 'panel' });
    this._heroes = heroes ?? [];
    this._onStart = onStart;

    // Party state — up to 4 slots
    this._partySlots = [...this._heroes, null, null, null, null].slice(0, 4);
    this._hiredNPCs = [];
    this._gold = 200;
    this._selectedScenario = 'standard';
    this._npcPool = [];

    // Generate 3 random NPCs for the tavern pool
    for (let i = 0; i < 3; i++) {
      this._npcPool.push(CharacterSystem.createNPC({ level: 1 }));
    }
  }

  build() {
    this.el.innerHTML = '';
    const root = document.createElement('div');
    root.className = 'pb-root';
    root.setAttribute('role', 'dialog');
    root.setAttribute('aria-label', 'Party Builder');

    root.appendChild(this._buildHeader());

    const content = document.createElement('div');
    content.className = 'pb-content';
    content.id = 'pb-content';
    this._colParty    = this._buildPartyColumn();
    this._colHire     = this._buildHireColumn();
    this._colScenario = this._buildScenarioColumn();
    content.appendChild(this._colParty);
    content.appendChild(this._colHire);
    content.appendChild(this._colScenario);
    root.appendChild(content);

    root.appendChild(this._buildFooter());
    this.el.appendChild(root);
    return this;
  }

  // ── Header ────────────────────────────────────────────────────────────────

  _buildHeader() {
    const header = document.createElement('div');
    header.className = 'pb-header';
    header.innerHTML = `
      <div>
        <div class="pb-header-title">Assemble Your Party</div>
        <div class="pb-header-sub">Hire companions, choose a scenario, and set out.</div>
      </div>
      <div class="pb-gold" id="pb-gold-display">Gold: ${this._gold}</div>
    `;
    return header;
  }

  _updateGoldDisplay() {
    const el = document.getElementById('pb-gold-display');
    if (el) el.textContent = `Gold: ${this._gold}`;
  }

  // ── Party column ──────────────────────────────────────────────────────────

  _buildPartyColumn() {
    const col = document.createElement('div');
    col.className = 'pb-col';
    col.id = 'pb-col-party';
    this._refreshPartyColumn(col);
    return col;
  }

  _refreshPartyColumn(col) {
    col = col ?? document.getElementById('pb-col-party');
    if (!col) return;
    col.innerHTML = `<div class="pb-col-title">Party (${this._partySlots.filter(Boolean).length}/4)</div>`;

    this._partySlots.forEach((char, i) => {
      if (!char) {
        const empty = document.createElement('div');
        empty.className = 'pb-char-card empty-slot';
        empty.textContent = `Slot ${i + 1} — Empty`;
        col.appendChild(empty);
        return;
      }

      const card = this._buildCharCard(char, i);
      col.appendChild(card);
    });

    // Manage Players button
    const manageBtn = document.createElement('button');
    manageBtn.type = 'button';
    manageBtn.className = 'pb-hire-btn';
    manageBtn.style.marginTop = '12px';
    manageBtn.style.width = '100%';
    manageBtn.id = 'pb-manage-players-btn';
    manageBtn.textContent = 'Manage Player Assignments';
    manageBtn.addEventListener('click', () => this._managePlayerAssignments());
    col.appendChild(manageBtn);
  }

  _buildCharCard(char, slotIndex) {
    const card = document.createElement('div');
    card.className = 'pb-char-card' + (char.isHero ? ' hero-card' : '');

    const race = CharacterSystem.getRace(char.race);
    const raceName = race?.name ?? char.race;

    // Player assignment
    let playerBadge = '';
    if (slotIndex === 0) playerBadge = '<span class="pb-player-badge p1">P1</span>';
    if (slotIndex === 1) playerBadge = '<span class="pb-player-badge p2">P2</span>';

    const attrs = char.attributes;
    const attrHtml = ['might','agility','intellect','wisdom','endurance','presence'].map(k => {
      const val = attrs[k] ?? 10;
      const shortName = k.slice(0,3).toUpperCase();
      return `<span class="pb-attr-pill">${shortName} <strong>${val}</strong></span>`;
    }).join('');

    card.innerHTML = `
      <div class="pb-char-name">${char.name} ${playerBadge}</div>
      <div class="pb-char-sub">${raceName} &bull; Level ${char.level}</div>
      <div class="pb-char-class">${char.class}</div>
      <div class="pb-char-attrs">${attrHtml}</div>
      ${!char.isHero ? `<div class="pb-wage-label">Wage: ${char.wage} gold/day</div>` : ''}
    `;

    // Dismiss button for hired NPCs
    if (!char.isHero) {
      const controls = document.createElement('div');
      controls.className = 'pb-char-controls';
      const dismissBtn = document.createElement('button');
      dismissBtn.type = 'button';
      dismissBtn.className = 'pb-dismiss-btn';
      dismissBtn.textContent = 'Dismiss';
      dismissBtn.addEventListener('click', () => {
        this._dismissNPC(char.id, slotIndex);
      });
      controls.appendChild(dismissBtn);
      card.appendChild(controls);
    }

    return card;
  }

  // ── Hire column ───────────────────────────────────────────────────────────

  _buildHireColumn() {
    const col = document.createElement('div');
    col.className = 'pb-col';
    col.id = 'pb-col-hire';
    this._refreshHireColumn(col);
    return col;
  }

  _refreshHireColumn(col) {
    col = col ?? document.getElementById('pb-col-hire');
    if (!col) return;
    col.innerHTML = `<div class="pb-col-title">Tavern — Hire Companions</div>`;

    if (this._npcPool.length === 0) {
      const empty = document.createElement('p');
      empty.style.cssText = 'font-size:0.75rem; color:#5a4a2a;';
      empty.textContent = 'No more companions available in this town.';
      col.appendChild(empty);
      return;
    }

    this._npcPool.forEach(npc => {
      const isHired = this._hiredNPCs.some(h => h.id === npc.id);
      if (isHired) return;

      const card = document.createElement('div');
      card.className = 'pb-char-card';
      card.style.marginBottom = '10px';

      const race = CharacterSystem.getRace(npc.race);
      const raceName = race?.name ?? npc.race;
      const hireCost = npc.wage * 3; // Upfront hire cost = 3 days wage

      const attrs = npc.attributes;
      const attrHtml = ['might','agility','intellect','wisdom','endurance','presence'].map(k => {
        const val = attrs[k] ?? 10;
        const shortName = k.slice(0,3).toUpperCase();
        return `<span class="pb-attr-pill">${shortName} <strong>${val}</strong></span>`;
      }).join('');

      card.innerHTML = `
        <div class="pb-char-name">${npc.name}</div>
        <div class="pb-char-sub">${raceName} &bull; Level ${npc.level}</div>
        <div class="pb-char-class">${npc.class}</div>
        <div class="pb-char-attrs">${attrHtml}</div>
        <div class="pb-wage-label">Hire cost: ${hireCost} gold &bull; Wage: ${npc.wage} gold/day</div>
      `;

      const hireBtn = document.createElement('button');
      hireBtn.type = 'button';
      hireBtn.className = 'pb-hire-btn';
      hireBtn.style.marginTop = '8px';
      hireBtn.textContent = `Hire (${hireCost} gold)`;
      hireBtn.disabled = this._gold < hireCost || this._partySlots.filter(Boolean).length >= 4;
      hireBtn.id = `pb-hire-btn-${npc.id}`;
      hireBtn.addEventListener('click', () => {
        this._hireNPC(npc, hireCost);
      });
      card.appendChild(hireBtn);
      col.appendChild(card);
    });

    if (this._npcPool.every(npc => this._hiredNPCs.some(h => h.id === npc.id))) {
      const empty = document.createElement('p');
      empty.style.cssText = 'font-size:0.75rem; color:#5a4a2a;';
      empty.textContent = 'All available companions hired.';
      col.appendChild(empty);
    }
  }

  _hireNPC(npc, cost) {
    const emptySlot = this._partySlots.findIndex(s => s === null);
    if (emptySlot === -1) {
      DebugLog.warn('[party] Cannot hire NPC: party full');
      return;
    }
    if (this._gold < cost) {
      DebugLog.warn('[party] Cannot hire NPC: insufficient gold');
      return;
    }

    this._gold -= cost;
    this._hiredNPCs.push(npc);
    this._partySlots[emptySlot] = npc;

    DebugLog.info(`[party] Hired NPC; name=${npc.name} cost=${cost} gold=${this._gold}`);

    this._updateGoldDisplay();
    this._refreshPartyColumn();
    this._refreshHireColumn();
    this._updateStartButton();
  }

  _dismissNPC(npcId, slotIndex) {
    const npc = this._hiredNPCs.find(n => n.id === npcId);
    if (!npc) return;

    this._hiredNPCs = this._hiredNPCs.filter(n => n.id !== npcId);
    this._partySlots[slotIndex] = null;

    // Compact party slots — move nulls to end
    const filled = this._partySlots.filter(Boolean);
    this._partySlots = [...filled, null, null, null, null].slice(0, 4);

    DebugLog.info(`[party] Dismissed NPC; name=${npc.name}`);

    this._refreshPartyColumn();
    this._refreshHireColumn();
    this._updateStartButton();
  }

  // ── Scenario column ───────────────────────────────────────────────────────

  _buildScenarioColumn() {
    const col = document.createElement('div');
    col.className = 'pb-col';
    col.id = 'pb-col-scenario';
    col.innerHTML = '<div class="pb-col-title">Starting Scenario</div>';

    STARTING_SCENARIOS.forEach(scenario => {
      const card = document.createElement('button');
      card.type = 'button';
      card.className = 'pb-scenario-card' + (this._selectedScenario === scenario.id ? ' selected' : '');
      card.dataset.scenarioId = scenario.id;
      card.innerHTML = `
        <div class="pb-scenario-name">${scenario.name}</div>
        <div class="pb-scenario-desc">${scenario.description}</div>
      `;
      card.addEventListener('click', () => {
        this._selectedScenario = scenario.id;
        col.querySelectorAll('.pb-scenario-card').forEach(c => c.classList.remove('selected'));
        card.classList.add('selected');
        this._refreshGearList(col);
      });
      col.appendChild(card);
    });

    // Starting gear
    const gearTitle = document.createElement('div');
    gearTitle.className = 'pb-col-title';
    gearTitle.style.marginTop = '16px';
    gearTitle.textContent = 'Starting Gear';
    gearTitle.id = 'pb-gear-title';
    col.appendChild(gearTitle);

    const gearList = document.createElement('div');
    gearList.className = 'pb-gear-list';
    gearList.id = 'pb-gear-list';
    col.appendChild(gearList);
    this._refreshGearList(col);

    return col;
  }

  _refreshGearList(col) {
    col = col ?? document.getElementById('pb-col-scenario');
    const list = col?.querySelector('#pb-gear-list') ?? document.getElementById('pb-gear-list');
    if (!list) return;
    list.innerHTML = '';

    const heroes = this._partySlots.filter(c => c && c.isHero);
    if (heroes.length === 0) {
      list.innerHTML = '<div class="pb-gear-item" style="color:#5a4a2a;">No heroes in party.</div>';
      return;
    }

    heroes.forEach(hero => {
      const adultBg = hero.background?.adult ?? 'soldier';
      const gear = BACKGROUND_GEAR[adultBg] ?? ['Basic Sword', 'Travel Rations'];
      const heroEl = document.createElement('div');
      heroEl.style.marginBottom = '8px';
      heroEl.innerHTML = `
        <div style="font-size:0.7rem; color:#8a7a50; margin-bottom:3px;">${hero.name}</div>
        ${gear.map(g => `<div class="pb-gear-item">• ${g}</div>`).join('')}
      `;
      list.appendChild(heroEl);
    });
  }

  // ── Player assignment ─────────────────────────────────────────────────────

  _managePlayerAssignments() {
    // Simple implementation: swap P1 and P2 if 2+ party members
    const filled = this._partySlots.filter(Boolean);
    if (filled.length < 2) {
      DebugLog.info('[party] Only one party member — P1 assignment unchanged');
      return;
    }
    // Swap slot 0 and slot 1 for demo
    const tmp = this._partySlots[0];
    this._partySlots[0] = this._partySlots[1];
    this._partySlots[1] = tmp;
    this._refreshPartyColumn();
    DebugLog.info('[party] Player assignments swapped');
  }

  // ── Footer ────────────────────────────────────────────────────────────────

  _buildFooter() {
    const footer = document.createElement('div');
    footer.className = 'pb-footer';

    const backBtn = document.createElement('button');
    backBtn.type = 'button';
    backBtn.className = 'pb-btn';
    backBtn.textContent = 'Back to Character Creation';
    backBtn.addEventListener('click', () => {
      DebugLog.info('[party] Back to charCreate');
      SceneManager.transition('charCreate');
    });

    this._statusMsg = document.createElement('span');
    this._statusMsg.className = 'pb-status-msg';
    this._statusMsg.textContent = 'Choose a scenario and start your adventure.';

    this._startBtn = document.createElement('button');
    this._startBtn.type = 'button';
    this._startBtn.className = 'pb-btn primary';
    this._startBtn.id = 'pb-btn-start';
    this._startBtn.textContent = 'Start Adventure';
    this._startBtn.addEventListener('click', () => this._startAdventure());
    this._updateStartButton();

    footer.appendChild(backBtn);
    footer.appendChild(this._statusMsg);
    footer.appendChild(this._startBtn);
    return footer;
  }

  _updateStartButton() {
    if (!this._startBtn) return;
    const hasHero = this._partySlots.some(c => c && c.isHero);
    this._startBtn.disabled = !hasHero;
  }

  // ── Start Adventure ───────────────────────────────────────────────────────

  _startAdventure() {
    const party = this._partySlots.filter(Boolean);
    if (party.length === 0) {
      DebugLog.warn('[party] Cannot start — no party members');
      return;
    }

    const scenario = STARTING_SCENARIOS.find(s => s.id === this._selectedScenario) ?? STARTING_SCENARIOS[0];
    const seed = Date.now();
    const params = { ...scenario.params, seed, startingRegionLevel: 1 };

    DebugLog.info(`[party] Starting adventure; scenario=${scenario.id} seed=${seed} party=${party.length}`);

    // Generate world
    let worldData;
    try {
      worldData = WorldGenerator.generate(params);
    } catch (err) {
      DebugLog.error(`[party] WorldGenerator failed: ${err.message}`);
      return;
    }

    // Initialize WorldState
    WorldState.init(worldData);

    // Assign characters to players: P1 → first hero, P2 → second, etc.
    CoopSystem.autoAssign();
    WorldState.playerCount = CoopSystem.getPlayerCount();

    // Expose systems globally so SaveSystem can access them
    window.__characterSystem = CharacterSystem;
    window.__coopSystem = CoopSystem;

    // Store party in EventBus/WorldState for the WorldMap scene to pick up
    EventBus.emit('party:set', { party, gold: this._gold });

    if (this._onStart) this._onStart({ party, worldData, gold: this._gold });

    SceneManager.transition('localMap', { regionId: worldData.startRegionId });
  }

  // ── Destroy ────────────────────────────────────────────────────────────────

  destroy() {
    super.destroy();
  }
}

// ─── PartyBuilderScene ────────────────────────────────────────────────────────

export default class PartyBuilderScene {
  constructor() {
    this._panel = null;
  }

  async init({ heroes = [] } = {}) {
    DebugLog.info('[boot] PartyBuilderScene init');

    injectStyles();

    if (!window.__debug) window.__debug = {};
    window.__debug.currentScene = 'partyBuilder';

    this._panel = new PartyBuilderPanel(heroes, ({ party, worldData, gold }) => {
      DebugLog.info(`[party] Adventure started; partySize=${party.length} gold=${gold}`);
    });

    this._panel.build();
    this._panel.show();

    DebugLog.info('[boot] PartyBuilderScene ready');
  }

  update(_dt) {}

  async destroy() {
    DebugLog.info('[boot] PartyBuilderScene destroy');
    if (this._panel) {
      this._panel.destroy();
      this._panel = null;
    }
    if (window.__debug && window.__debug.currentScene === 'partyBuilder') {
      window.__debug.currentScene = null;
    }
  }
}
